# Escribir skills
created = 0
for skill in SKILLS:
    name = skill["name"]
    filepath = SKILLS_DIR / f"{name}.json"
    if not filepath.exists():
        with open(filepath, "w", encoding="utf-8") as f:
            json.dump(skill, f, ensure_ascii=False, indent=2)
        created += 1
    else:
        # Sobreescribir — siempre actualizar
        with open(filepath, "w", encoding="utf-8") as f:
            json.dump(skill, f, ensure_ascii=False, indent=2)
        created += 1

print(f"✅ {created} skills generadas en {SKILLS_DIR}")
print(f"📁 Total en directorio: {len(list(SKILLS_DIR.glob('*.json')))}")

# Categorías resumen
cats = {}
for s in SKILLS:
    cat = s["name"].split("-")[0]
    cats[cat] = cats.get(cat, 0) + 1
for cat, n in sorted(cats.items(), key=lambda x: -x[1]):
    print(f"  {cat}: {n} skills")
